local LxBaseMgr = require("LApp.Manager.LxBaseMgr")
---@class LxHttpMgr:LxBaseMgr
local LxHttpMgr = classX("LxHttpMgr", LxBaseMgr)

function LxHttpMgr:Initialize()
    LxBaseMgr.Initialize(self)

    ---@type LxHttp[]
    self._https = {}
end

function LxHttpMgr:AddHttp(http)
    table.insert(self._https, http)
end

function LxHttpMgr:OnUpdate()
    if self._isDisposed then return end

    local removeList = {}
    local https = self._https
    if https == nil or #https == 0 then return end

    for k,v in ipairs(https) do
        if self._isDisposed then return end
        
        if v:IsEnd() then
            table.insert(removeList, k)
        else
            v:OnUpdate()
        end
    end

    for k=#removeList, 1, -1 do
        local http = table.remove(https, removeList[k])
        http:Dispose()
    end
end

function LxHttpMgr:Dispose()
    for k,v in ipairs(self._https) do
        v:Dispose()
    end
    LxBaseMgr.Dispose(self)
end

---热更lua 后热重载 调用
function LxHttpMgr:ClearAllHttps()
    for k,v in ipairs(self._https) do
        v:Dispose()
    end
    self._https = {}
end

---获取http，获取后不请求，请不要使用该接口
function LxHttpMgr:NewHttp()
    local http = require("LApp.component.LxHttp"):New()
    self:AddHttp(http)
    http:Initialize()
    return http
end

function LxHttpMgr:DoGet(urlList, okFunc, notTimestamp, retryMax)
    local http = require("LApp.component.LxHttp"):New()
    self:AddHttp(http)
    http:Initialize()
    http:InitHttp(urlList, okFunc)
    http:SetFixTimestamp(not notTimestamp)
    if retryMax then
        http:SetRetryCount(retryMax)
    end
    http:DoGet()
end

